function solve(n: number, k: number): number {
    const memo: Map<number, number> = new Map();

    function popcountDepth(x: number): number {
        if (memo.has(x)) {
            return memo.get(x)!;
        }

        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = current.toString(2).split('1').length - 1;
            depth++;
        }
        memo.set(x, depth);
        return depth;
    }

    let count = 0;
    for (let x = 1; x <= n; x++) {
        if (popcountDepth(x) === k) {
            count++;
        }
    }
    return count;
}
